const action = msg.payload && msg.payload.action;
const value  = msg.payload && msg.payload.value;

let desde, hasta;

if (msg.payload && msg.payload.desde) {
    desde = new Date(msg.payload.desde);
    hasta = new Date(msg.payload.hasta);

} else if (action === 'set_horas') {
    const horas = Math.min(Number(value), 720);
    flow.set('insight_horas', horas);
    hasta = new Date();
    desde = new Date(Date.now() - horas * 3600000);

} else if (action === 'refresh' || action === 'get_state') {
    const horas = flow.get('insight_horas') || 0.25;
    hasta = new Date();
    desde = new Date(Date.now() - horas * 3600000);

} else if (action === 'set_absoluto' && value) {
    desde = new Date(value.desde);
    hasta = new Date(value.hasta);

} else if (action === 'save_state' && value) {
    if (value.tpAbsoluto && value.tpFrom && value.tpTo) {
        desde = new Date(value.tpFrom);
        hasta = new Date(value.tpTo);
    } else {
        const horas = value.rangoActivo || 0.25;
        flow.set('insight_horas', horas);
        hasta = new Date();
        desde = new Date(Date.now() - horas * 3600000);
    }

} else {
    return null;
}

if (!desde || !hasta || hasta <= desde) return null;

const colecciones = ['insight'];

const msgs = colecciones.map((col, i) => ({
    topic: col,
    payload: [
        { time: { $gte: desde, $lte: hasta } },
        { sort: { time: 1 } }
    ],
    parts: {
        id:    Date.now(),
        type:  'array',
        count: colecciones.length,
        index: i
    }
}));

return [msgs];

const paleta = [
    '#58a6ff','#3fb950','#f78166','#d2a8ff','#ffa657',
    '#79c0ff','#56d364','#ff7b72','#bc8cff','#ffb366',
    '#388bfd','#2ea043','#da3633','#8957e5'
];

const toMs = d => new Date(d.time).getTime();
const toKW = w => (w != null) ? parseFloat((w / 1000).toFixed(3)) : null;
const toF  = (v, dec) => (v != null) ? parseFloat(parseFloat(v).toFixed(dec)) : null;

const mkSerie = (name, metric, yIdx, color, data, dash) => ({
    name, metric, type: 'line', yAxisIndex: yIdx, data,
    smooth: true, connectNulls: false,
    lineStyle: { width: 1, color, ...(dash ? { type: dash } : {}) },
    itemStyle: { color }
});

// Normalizar entrada: puede llegar como array plano o como {col: [docs]}
let resultados = {};
if (Array.isArray(msg.payload)) {
    resultados = { [msg.topic || 'insight']: msg.payload };
} else {
    resultados = msg.payload;
}

const series    = [];
const colLabels = {};
let   colIdx    = 0;

for (const [col, docs] of Object.entries(resultados)) {
    if (!docs || docs.length === 0) { colIdx++; continue; }

    const label = col;
    const color = paleta[colIdx % paleta.length];
    const m0    = docs[0]?.metrics || {};

    if (m0.power !== undefined) {
        const data = docs.map(d => [toMs(d), toKW(d.metrics?.power)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW', 'kW', 0, color, data));
    }
    if (m0.power_a !== undefined) {
        const data = docs.map(d => [toMs(d), toKW(d.metrics?.power_a)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-A', 'kW-A', 0, color, data, 'dashed'));
    }
    if (m0.power_b !== undefined && m0.power_b !== null) {
        const data = docs.map(d => [toMs(d), toKW(d.metrics?.power_b)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-B', 'kW-B', 0, color, data, 'dotted'));
    }
    if (m0.power_c !== undefined && m0.power_c !== null) {
        const data = docs.map(d => [toMs(d), toKW(d.metrics?.power_c)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-C', 'kW-C', 0, color, data, 'dotted'));
    }
    if (m0.voltage_a !== undefined) {
        const data = docs.map(d => [toMs(d), toF(d.metrics?.voltage_a, 1)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · V', 'V', 2, color, data));
    }
    if (m0.current_a !== undefined) {
        const data = docs.map(d => [toMs(d), toF(d.metrics?.current_a, 2)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · A', 'A', 3, color, data));
    }
    if (m0.ac_frequency !== undefined) {
        const data = docs.map(d => [toMs(d), toF(d.metrics?.ac_frequency, 2)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie('Red · Hz', 'Hz', 1, color, data));
    }
    if (m0.temperature !== undefined) {
        const data = docs.map(d => [toMs(d), toF(d.metrics?.temperature, 1)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie('Temperatura · °C', '°C', 1, color, data));
    }
    if (m0.power_factor !== undefined) {
        const data = docs.map(d => [toMs(d), toF((d.metrics?.power_factor) / 100, 3)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · cos φ', 'cos φ', 1, color, data));
    }

    colLabels[label] = col;
    colIdx++;
}

if (series.find(s => s.metric === '°C'))  colLabels['Temperatura'] = 'temperatura';
if (series.find(s => s.metric === 'Hz'))  colLabels['Red']         = 'red';

msg.topic   = 'insight/data';
msg.payload = { series, colLabels };
return msg;

