//almacenar el dato original
const originalPayload = msg.payload;
// formatear a modo time series de mongo dB
msg.payload = [{
    time: new Date(),
    data: originalPayload
}]
return msg;

const deviceType = msg.topic;
const raw = msg.payload[0].data;

const normalized = {
    time: new Date(),
    device: deviceType,
    device_model: raw.device_model || "unknown",
    metrics: {
        voltage:        raw.voltage || raw.voltage_a || null,
        voltage_a:      raw.voltage_a || null,
        voltage_b:      raw.voltage_b || null,
        voltage_c:      raw.voltage_c || null,
        current:        raw.current || null,
        current_a:      raw.current_a || null,
        current_b:      raw.current_b || null,
        current_c:      raw.current_c || null,
        power:          raw.power || null,
        power_a:        raw.power_a || null,
        power_b:        raw.power_b || null,
        power_c:        raw.power_c || null,
        power_factor:   raw.power_factor || null,
        ac_frequency:   raw.ac_frequency || null,
        temperature:    raw.temperature || null
    },
    raw_data: raw
};

msg.payload = normalized;
return msg;
